ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/banking#>
PREFIX p: <http://ambrosia.example.org/banking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?mt WHERE { ?b a :Banks ; p:Management_Team ?mt . ?c p:hasBanks ?b . ?l p:hasCustomers ?c ; p:monthlyPayment ?mp } GROUP BY ?mt ORDER BY DESC(MAX(xsd:double(?mp))) LIMIT 1 }
  full: { SELECT ?ceo ?mt WHERE { ?b a :Banks ; p:Ceo ?ceo ; p:Management_Team ?mt . ?c p:hasBanks ?b . ?l p:hasCustomers ?c ; p:monthlyPayment ?mp } GROUP BY ?ceo ?mt ORDER BY DESC(MAX(xsd:double(?mp))) LIMIT 1 }
  component_2: { SELECT ?ceo WHERE { ?b a :Banks ; p:Ceo ?ceo . ?c p:hasBanks ?b . ?l p:hasCustomers ?c ; p:monthlyPayment ?mp } GROUP BY ?ceo ORDER BY DESC(MAX(xsd:double(?mp))) LIMIT 1 }
}
